message.content:
@startuml
skinparam ClassDiagram labelStyle "C"

title Modulo-matrícula/Informática

class Matrícula {
    -cliente: Client
    -tempo: Int
    -quadra: Turma
}

class Aluno {
    -id: Int
    -nome: String
    -locação: List<Matrícula>
}

class ControleNúmeroMatrícula {
    -quantidade: Int
}

class Turma {
    -numero: Int
    -aluguel: Matrícula
    -ginásio: Curso
}

class Curso {
    -nome: String
    -quadra: List<Turma>
}

Matrícula --> Aluno : composição 1
Aluno --> Matrícula : composição 1
Matrícula --> Turma : composição 1
Turma --> Curso : composição 1
Curso --> Turma : composição 1
ControleNúmeroMatrícula --> Turma : composição 1

@enduml
